        public String enterpriseAddress;

        public BigInteger score;

        public BigInteger previousScore;

        public BigInteger calculationTime;

        public byte[] calculationFactors;

        public ScoreRecord(Address enterpriseAddress, Uint256 score, Uint256 previousScore,
                Uint256 calculationTime, Bytes32 calculationFactors) {
            super(enterpriseAddress,score,previousScore,calculationTime,calculationFactors);
            this.enterpriseAddress = enterpriseAddress.getValue();
            this.score = score.getValue();
            this.previousScore = previousScore.getValue();
            this.calculationTime = calculationTime.getValue();
            this.calculationFactors = calculationFactors.getValue();
        }

